const QUESTIONS_CISM_C5 = [
  { id:10841, domain:1, level:2, question:"Which governance framework aligns IT objectives with business goals through a structured approach to value delivery?", options:["A ISO 27001","B ITIL","NIST CSF","D COBIT"], correct:3, explanation:"COBIT (Control Objectives for Information and Related Technologies) is specifically designed to align IT governance with business objectives and ensure value delivery." },
  { id:10842, domain:1, level:1, question:"What is the primary role of a board of directors in information security governance?", options:["A Setting strategic direction and oversight","B Managing day-to-day security operations","Conducting vulnerability assessments","D Implementing technical security controls"], correct:0, explanation:"The board of directors is responsible for setting strategic direction and providing oversight of the organization's security posture, not hands-on technical implementation." },
  { id:10843, domain:1, level:2, question:"Which document formally defines the scope, objectives, and accountability for information security within an organization?", options:["Security procedures manual","B Information security policy","Risk register","D Business continuity plan"], correct:1, explanation:"The information security policy is the top-level document that establishes scope, objectives, and accountability for security across the organization." },
  { id:10844, domain:1, level:3, question:"An organization's CISO discovers that security initiatives consistently lack funding. What governance mechanism most directly addresses this issue?", options:["Updating the risk register","B Revising technical standards","Deploying a SIEM solution","D Establishing a security steering committee"], correct:3, explanation:"A security steering committee provides the formal governance structure to ensure executive sponsorship, resource allocation, and cross-functional support for security initiatives." },
  { id:10845, domain:1, level:1, question:"What does 'tone at the top' refer to in the context of information security governance?", options:["A Executive leadership's commitment to security culture","B Network perimeter security posture","The highest classification level of data","Technical security benchmarks"], correct:0, explanation:"'Tone at the top' refers to the attitude and commitment of senior leadership toward security, which influences the organization's overall security culture." },
  { id:10846, domain:1, level:2, question:"Which metric best demonstrates the business value of an information security program to executive stakeholders?", options:["Number of firewall rules configured","B Percentage reduction in security incidents with associated cost avoidance","Total number of patches applied","D Average antivirus scan time"], correct:1, explanation:"Business-oriented metrics such as cost avoidance from reduced incidents directly communicate security value in terms executives can use for decision-making." },
  { id:10847, domain:1, level:2, question:"What is the purpose of a security governance framework?", options:["To replace existing security tools","B To provide a structured approach for managing security decisions and accountability","To document all network configurations","D To automate patch management"], correct:1, explanation:"A security governance framework provides the structure, processes, and accountability mechanisms needed to make and enforce consistent security decisions." },
  { id:10848, domain:1, level:1, question:"Which of the following best describes the relationship between information security governance and corporate governance?", options:["They are entirely separate functions","B They have no formal relationship","C Information security governance is a subset of corporate governance","D Corporate governance is subordinate to security governance"], correct:2, explanation:"Information security governance is a component of overall corporate governance, ensuring security objectives align with and support broader organizational goals." },
  { id:10849, domain:1, level:3, question:"A CISO is asked to justify a significant security investment to the board. Which approach is MOST effective?", options:["Present a detailed list of vulnerabilities discovered","B Describe the technical architecture of the proposed solution","C Frame the investment in terms of risk reduction and business enablement","Compare the number of security tools to industry peers"], correct:2, explanation:"Board-level communication is most effective when security investments are framed as risk reduction and business enablement rather than technical details." },
  { id:10850, domain:1, level:2, question:"Which governance principle ensures that individuals are held responsible for their security-related decisions and actions?", options:["A Accountability","B Confidentiality","Availability","Integrity"], correct:0, explanation:"Accountability in governance means that individuals and roles can be held responsible for their decisions, actions, and outcomes related to information security." },
  { id:10851, domain:1, level:1, question:"What is the primary purpose of an information security charter?", options:["To list all security vulnerabilities","To formally establish the authority and responsibilities of the security function","To document network topology","To define technical encryption standards"], correct:1, explanation:"An information security charter formally grants authority to the security function and defines its responsibilities, reporting structure, and mandate within the organization." },
  { id:10852, domain:1, level:2, question:"Which of the following BEST describes the concept of segregation of duties in security governance?", options:["Encrypting data at rest and in transit","Dividing critical tasks among multiple individuals to prevent fraud or error","Backing up data to multiple locations","Requiring two-factor authentication for all users"], correct:1, explanation:"Segregation of duties divides sensitive or critical tasks among multiple people so no single individual can commit and conceal fraud or error." },
  { id:10853, domain:1, level:3, question:"An organization is expanding into a new country with strict data sovereignty laws. What governance action should the CISO take FIRST?", options:["Deploy additional firewalls in the new country","B Immediately encrypt all data transferred to the new region","C Hire local security staff","D Assess the legal and regulatory requirements and update the governance framework accordingly"], correct:3, explanation:"Governance must first understand the legal and regulatory landscape to ensure security policies and practices comply with local requirements before operational changes." },
  { id:10854, domain:1, level:1, question:"What does the principle of 'least privilege' require in access governance?", options:["All users share a common account","B Users are granted only the minimum access necessary to perform their job functions","Administrators have unrestricted access","D Access is reviewed annually"], correct:1, explanation:"Least privilege limits user access rights to only what is necessary for their job, reducing the attack surface and potential for misuse." },
  { id:10855, domain:1, level:2, question:"Which of the following is an example of a security governance outcome rather than a governance activity?", options:["Conducting a policy review","B culture where employees report security concerns freely","C Holding a steering committee meeting","Assigning a data owner to each system"], correct:1, explanation:"A security-aware culture where employees voluntarily report concerns is an outcome of governance activities, not the activity itself." },
  { id:10856, domain:1, level:2, question:"What is the significance of aligning information security strategy with business strategy?", options:["A It ensures security investments support and enable organizational objectives","B It eliminates the need for a security budget","It removes all security risks","It replaces the need for technical controls"], correct:0, explanation:"Aligning security strategy with business strategy ensures that security investments contribute to organizational goals and are prioritized based on business value." },
  { id:10857, domain:1, level:3, question:"A merger results in two organizations with conflicting security policies. What is the BEST governance approach?", options:["A Keep both policy sets in place indefinitely","B Adopt the acquiring company's policies without review","C Conduct a gap analysis and develop a unified governance framework","Delegate policy decisions to individual department heads"], correct:2, explanation:"A gap analysis identifies conflicts and areas of alignment, enabling the creation of a unified governance framework that serves the combined organization." },
  { id:10858, domain:1, level:1, question:"Which role is typically responsible for approving the information security policy?", options:["Security analyst","B Help desk manager","C Chief Information Security Officer","D Board of directors or senior executive"], correct:3, explanation:"The information security policy requires approval at the highest levels of authority—typically the board of directors or a senior executive—to ensure organizational buy-in and enforcement." },
  { id:10859, domain:1, level:2, question:"What is the primary objective of an information security strategy?", options:["To purchase the latest security technologies","To define how security will achieve its mission and support business objectives over time","To eliminate all identified vulnerabilities immediately","To document all security incidents"], correct:1, explanation:"An information security strategy defines the roadmap and objectives that guide how security will fulfill its mission and support the organization's business goals." },
  { id:10860, domain:1, level:3, question:"Which governance measure BEST ensures that security controls remain aligned with the changing threat landscape?", options:["A Continuous monitoring and periodic strategy reassessment","B Static annual policy reviews","One-time risk assessment at project initiation","Deploying the same controls across all business units"], correct:0, explanation:"Continuous monitoring combined with periodic strategy reassessment ensures governance remains responsive to evolving threats and business changes." },
  { id:10861, domain:2, level:1, question:"What is the PRIMARY goal of information risk management?", options:["A Identifying and mitigating risks to an acceptable level","B Eliminating all risks to the organization","Transferring all risk to third parties","Documenting every threat in the risk register"], correct:0, explanation:"Risk management aims to reduce risks to an acceptable level rather than eliminating all risk, which is neither feasible nor cost-effective." },
  { id:10862, domain:2, level:2, question:"Which risk treatment option involves purchasing cyber liability insurance?", options:["Risk avoidance","B Risk transfer","C Risk acceptance","Risk mitigation"], correct:1, explanation:"Purchasing insurance transfers the financial consequences of a risk to a third party (the insurer), which is a risk transfer strategy." },
  { id:10863, domain:2, level:1, question:"What does 'inherent risk' represent in information risk management?", options:["Risk remaining after controls are applied","B The risk of a control failing","C The risk that exists before any controls are implemented","Residual risk after audit findings"], correct:2, explanation:"Inherent risk is the level of risk that exists in the absence of any controls or mitigating factors." },
  { id:10864, domain:2, level:2, question:"Which of the following BEST describes a risk appetite statement?", options:["A list of all organizational assets","B register of all known threats","C The types and amount of risk an organization is willing to accept in pursuit of its objectives","A technical security standard"], correct:2, explanation:"A risk appetite statement formally communicates the level and types of risk an organization is prepared to accept while pursuing its strategic goals." },
  { id:10865, domain:2, level:3, question:"An organization has identified a critical vulnerability in a legacy system that cannot be patched. Which risk treatment is MOST appropriate?", options:["Ignore the risk since patching is impossible","B Implement compensating controls and formally accept the residual risk","C Accept the risk without any compensating controls","Immediately decommission the system"], correct:1, explanation:"When patching is not possible, compensating controls reduce residual risk, and formal acceptance documents management's informed decision." },
  { id:10866, domain:2, level:1, question:"What is 'residual risk'?", options:["The risk before any controls are applied","B The risk that remains after controls have been implemented","C The risk of a business continuity failure","The maximum possible loss from an event"], correct:1, explanation:"Residual risk is the level of risk remaining after controls have been implemented and other risk treatment actions have been taken." },
  { id:10867, domain:2, level:2, question:"Which qualitative risk analysis method uses a matrix to prioritize risks based on likelihood and impact?", options:["A Risk heat map","B Monte Carlo simulation","C Delphi technique","Fault tree analysis"], correct:0, explanation:"A risk heat map (or risk matrix) plots risks by likelihood and impact to visually prioritize them for treatment decisions." },
  { id:10868, domain:2, level:2, question:"What is the purpose of a threat modeling exercise?", options:["To test employee phishing awareness","B To identify and prioritize threats to a system or application","C To document all current security controls","To assess third-party vendor compliance"], correct:1, explanation:"Threat modeling systematically identifies potential threats to a system, helping security teams prioritize mitigations based on the most relevant attack vectors." },
  { id:10869, domain:2, level:3, question:"A risk assessment reveals that the cost of controls exceeds the potential loss. What is the MOST appropriate course of action?", options:["A Accept the risk and document the decision","B Implement the controls regardless of cost","Transfer the risk to a third party","Escalate to the board for mandatory remediation"], correct:0, explanation:"When control costs exceed potential loss, risk acceptance is economically justified, provided the decision is formally documented and approved by appropriate management." },
  { id:10870, domain:2, level:1, question:"What does 'vulnerability' mean in the context of information risk?", options:["A known attack being actively exploited","B The likelihood of a threat occurring","C The financial impact of a security incident","D weakness that could be exploited by a threat"], correct:3, explanation:"A vulnerability is a weakness in a system, process, or control that could be exploited by a threat to cause harm." },
  { id:10871, domain:2, level:2, question:"Which of the following is an example of a quantitative risk analysis technique?", options:["Risk heat map","B Brainstorming session","SWOT analysis","D Annual Loss Expectancy (ALE) calculation"], correct:3, explanation:"ALE (Annual Loss Expectancy) is a quantitative technique that assigns monetary values to risk by multiplying annual rate of occurrence by single loss expectancy." },
  { id:10872, domain:2, level:3, question:"A CISO is evaluating two risk treatment options of equal cost. Option A reduces likelihood; Option B reduces impact. Which factor should guide the decision?", options:["Option A is always preferable","Option B is always preferable","The nature of the risk and which dimension most significantly affects total risk exposure","The preference of the IT department"], correct:2, explanation:"The optimal choice depends on the specific risk profile; if impact drives overall risk exposure more than likelihood, reducing impact provides greater benefit, and vice versa." },
  { id:10873, domain:2, level:1, question:"What is the primary output of a risk assessment?", options:["A prioritized list of risks and recommended treatments","B list of security policies","A completed audit report","A network vulnerability scan report"], correct:0, explanation:"A risk assessment produces a prioritized inventory of identified risks along with recommended treatment options to guide management decisions." },
  { id:10874, domain:2, level:2, question:"Which concept describes the maximum tolerable downtime for a critical business process?", options:["Recovery Point Objective (RPO)","B Single Loss Expectancy (SLE)","Mean Time Between Failures (MTBF)","D Recovery Time Objective (RTO)"], correct:3, explanation:"RTO defines the maximum acceptable time a business process can be offline following a disruption before the impact becomes unacceptable." },
  { id:10875, domain:2, level:2, question:"What is the purpose of a risk register?", options:["A To document, monitor, and manage identified risks over time","B To track IT project milestones","To store cryptographic keys","To record security training completions"], correct:0, explanation:"A risk register is a living document that records identified risks, their assessments, treatment decisions, owners, and current status for ongoing management." },
  { id:10876, domain:2, level:3, question:"During a third-party risk assessment, a critical vendor is found to have inadequate security controls. The vendor is the only provider of a specialized service. What is the BEST approach?", options:["Immediately terminate the vendor relationship","Accept the risk and continue without action","Work with the vendor to define remediation timelines and implement compensating controls until improvement is achieved","Replace the vendor with an internal solution"], correct:2, explanation:"When a critical vendor cannot be replaced, a collaborative remediation plan with compensating controls and defined timelines manages the risk while maintaining the business relationship." },
  { id:10877, domain:2, level:1, question:"What does 'risk tolerance' refer to?", options:["The maximum number of security incidents per year","B The ability to recover from a security incident","C The acceptable variation in outcomes around the risk appetite","The total cost of implementing security controls"], correct:2, explanation:"Risk tolerance defines the acceptable range of deviation from the risk appetite, representing the boundaries within which the organization can operate." },
  { id:10878, domain:2, level:2, question:"Which of the following BEST describes a key risk indicator (KRI)?", options:["A metric that measures control effectiveness after an incident","B compliance checklist item","A post-incident report summary","D forward-looking metric that signals increasing risk exposure"], correct:3, explanation:"KRIs are metrics that provide early warning signals of increasing risk, enabling proactive management before risk events materialize." },
  { id:10879, domain:2, level:3, question:"An organization's risk assessment methodology uses only qualitative analysis. A new board member requests quantitative data. What is the BEST response?", options:["A Supplement the qualitative approach with quantitative analysis for high-priority risks","Immediately replace all qualitative methods with quantitative ones","C Refuse, as qualitative analysis is sufficient","Defer to external auditors for quantitative data"], correct:0, explanation:"A hybrid approach uses quantitative analysis where greater precision is needed for high-stakes decisions, while retaining qualitative methods for broader risk categorization." },
  { id:10880, domain:2, level:2, question:"What is the role of the risk owner in an information risk management program?", options:["A To accept accountability for managing a specific risk and ensuring treatment is implemented","B To conduct employee security training","To develop security policies","D To perform penetration testing"], correct:0, explanation:"The risk owner is accountable for a specific risk, ensuring that appropriate treatment actions are taken and monitored to keep residual risk within tolerance." },
  { id:10881, domain:3, level:1, question:"What is the primary purpose of an information security program?", options:["To deploy security tools and technologies","B To systematically manage security controls aligned with business objectives","C To pass compliance audits","To replace the need for risk assessments"], correct:1, explanation:"An information security program provides the organized, ongoing management of security controls, processes, and people in alignment with organizational objectives." },
  { id:10882, domain:3, level:2, question:"Which framework is MOST widely used to establish a baseline of cybersecurity practices for program development?", options:["PMBOK","B NIST Cybersecurity Framework (CSF)","C ITIL","Six Sigma"], correct:1, explanation:"The NIST CSF provides a widely adopted framework of core functions (Identify, Protect, Detect, Respond, Recover) for organizing cybersecurity program activities." },
  { id:10883, domain:3, level:2, question:"What does a security program roadmap primarily define?", options:["A The technical specifications for each security tool","B The sequence and timeline of planned security initiatives aligned to strategy","The list of all known vulnerabilities","The budget for each security team member"], correct:1, explanation:"A security program roadmap outlines the prioritized sequence of initiatives, milestones, and timelines needed to mature the security program toward its strategic objectives." },
  { id:10884, domain:3, level:3, question:"A CISM practitioner is building a metrics program. Which characteristic MOST distinguishes a useful security metric from a poor one?", options:["A It drives actionable decisions and tracks progress toward defined objectives","It measures something easily available regardless of relevance","C It is technically complex to calculate","It requires a large volume of raw data"], correct:0, explanation:"Effective security metrics are actionable—they inform specific decisions, track goal achievement, and provide meaningful insight rather than simply being easy to collect." },
  { id:10885, domain:3, level:1, question:"What is the purpose of security awareness training?", options:["A To document security incidents","B To replace technical security controls","To automate patch management","D To educate employees so they recognize and respond appropriately to security threats"], correct:3, explanation:"Security awareness training builds employee knowledge and behaviors that reduce human-related risks such as phishing, social engineering, and policy violations." },
  { id:10886, domain:3, level:2, question:"Which security program component ensures that security requirements are incorporated into new systems from the start?", options:["Incident response","Security architecture review in the SDLC","Vulnerability scanning","Access certification"], correct:1, explanation:"Integrating security architecture reviews into the Software Development Life Cycle ensures security requirements are addressed during design rather than as costly afterthoughts." },
  { id:10887, domain:3, level:2, question:"What is the primary objective of a security operations center (SOC)?", options:["To develop security policies","B To manage vendor contracts","To conduct annual risk assessments","D To monitor, detect, and respond to security events in real time"], correct:3, explanation:"A SOC provides continuous monitoring and real-time response capability to detect and contain security incidents before they escalate." },
  { id:10888, domain:3, level:3, question:"An organization must demonstrate program maturity to regulators. Which tool BEST communicates current capability and improvement trajectory?", options:["A copy of the information security policy","B list of security technologies deployed","The number of security incidents in the past year","D Capability Maturity Model (CMM) assessment with improvement roadmap"], correct:3, explanation:"A CMM assessment objectively measures current program maturity across defined dimensions and an improvement roadmap shows the planned path to higher maturity levels." },
  { id:10889, domain:3, level:1, question:"What does 'defense in depth' mean as a security program principle?", options:["A Layering multiple security controls so that failure of one does not compromise the whole","B Encrypting all data with the strongest available algorithm","C Using one very strong security control","Relying solely on perimeter defenses"], correct:0, explanation:"Defense in depth employs multiple, overlapping layers of security controls so that if one control fails, others continue to protect the organization." },
  { id:10890, domain:3, level:2, question:"Which activity BEST measures the effectiveness of a security awareness program?", options:["Number of training sessions delivered","B Number of policies published","Total hours of training content available","D Simulated phishing click rates and post-training behavior changes"], correct:3, explanation:"Behavioral metrics such as phishing simulation results directly measure whether awareness training changes employee actions, which is the ultimate goal." },
  { id:10891, domain:3, level:3, question:"A security manager discovers that business units are implementing their own security tools without involving the security team. What program management action addresses this MOST effectively?", options:["Issue a memo banning unauthorized tools","B Report all violators to HR","C Implement a formal security review process integrated into procurement and project initiation","Lock down administrator accounts"], correct:2, explanation:"Integrating a mandatory security review into procurement and project initiation ensures security involvement in all technology decisions without simply issuing prohibitive policies." },
  { id:10892, domain:3, level:1, question:"What is the role of key performance indicators (KPIs) in a security program?", options:["A To prioritize vulnerability remediation","B To identify threats to the organization","To document security incidents","D To measure the performance and effectiveness of security activities"], correct:3, explanation:"KPIs measure how well the security program is achieving its defined goals, enabling management to track progress and identify areas needing improvement." },
  { id:10893, domain:3, level:2, question:"Which document translates high-level security policy into specific, actionable requirements for a particular technology or process?", options:["Security policy","Security standard","Security procedure","Security guideline"], correct:1, explanation:"Security standards provide specific, mandatory requirements that implement policy directives for particular technologies, processes, or environments." },
  { id:10894, domain:3, level:2, question:"What is the purpose of a security program charter?", options:["To document all vulnerabilities found during an assessment","B To list all security tools and their configurations","C To formally authorize the security program, define its scope, and grant necessary authority","To serve as the incident response plan"], correct:2, explanation:"A security program charter formally establishes the program's mandate, authority, scope, and accountability within the organization." },
  { id:10895, domain:3, level:3, question:"After a major acquisition, the CISM practitioner must integrate the acquired company's security program. What is the FIRST step?", options:["Replace all acquired company security tools","B Assess the maturity and gaps of the acquired company's security program against the parent organization's standards","Issue all employees of the acquired company the parent company's security policies","D Immediately conduct a full penetration test of the acquired company's systems"], correct:1, explanation:"A maturity and gap assessment establishes a baseline understanding of differences, enabling an informed, prioritized integration plan." },
  { id:10896, domain:3, level:1, question:"What is the primary purpose of a vulnerability management program?", options:["A To systematically identify, prioritize, and remediate security weaknesses","B To replace patch management entirely","C To eliminate all system vulnerabilities immediately","To document all security incidents"], correct:0, explanation:"A vulnerability management program provides a structured process for continuously identifying, assessing, and remediating weaknesses before they can be exploited." },
  { id:10897, domain:3, level:2, question:"Which security program element provides assurance that controls are operating as intended?", options:["A Employee onboarding training","B Security policy development","Threat intelligence subscription","D Security control monitoring and testing"], correct:3, explanation:"Ongoing monitoring and periodic testing of controls provide assurance that they function correctly and continue to meet their stated objectives." },
  { id:10898, domain:3, level:3, question:"A CISM practitioner is asked to reduce the security program budget by 20% without increasing risk significantly. What is the BEST approach?", options:["Eliminate all user awareness training","Randomly cut 20% of control activities","Conduct a cost-benefit analysis to identify least-effective controls for reduction or consolidation","Defer all new security initiatives indefinitely"], correct:2, explanation:"A cost-benefit analysis identifies which controls provide the least risk reduction per dollar spent, enabling informed cuts that minimize overall risk impact." },
  { id:10899, domain:3, level:2, question:"What is the primary benefit of integrating security into the change management process?", options:["It slows down all changes to the organization","It ensures security impacts are evaluated before changes are implemented","It replaces the need for a security operations center","It automates vulnerability scanning"], correct:1, explanation:"Integrating security into change management ensures that security implications are assessed and mitigations applied before changes are made, preventing new vulnerabilities." },
  { id:10900, domain:3, level:1, question:"What is the purpose of a data classification policy?", options:["A To categorize data based on sensitivity so appropriate controls can be applied","B To back up all data to cloud storage","C To encrypt all organizational data","To assign every data asset a financial value"], correct:0, explanation:"Data classification categorizes information by sensitivity level, enabling the organization to apply proportionate protection controls to each category." },
  { id:10901, domain:4, level:1, question:"What is the PRIMARY objective of an incident response plan?", options:["A To document all vulnerabilities in the organization","B To prevent all security incidents from occurring","C To provide a structured approach to containing, eradicating, and recovering from security incidents","To replace the need for security monitoring"], correct:2, explanation:"An incident response plan provides the structured processes and defined roles needed to effectively manage security incidents from detection through recovery." },
  { id:10902, domain:4, level:2, question:"Which phase of the incident response lifecycle involves preserving evidence and documenting the incident timeline?", options:["Preparation","Eradication","C Containment and forensic analysis","D Recovery"], correct:2, explanation:"During containment, security teams also perform forensic analysis to preserve evidence and document the incident timeline before eradication and recovery steps." },
  { id:10903, domain:4, level:1, question:"What is the purpose of a 'lessons learned' review after a security incident?", options:["To assign blame to responsible parties","B To identify improvements to prevent recurrence and improve response capabilities","To document the financial losses from the incident","D To notify regulatory authorities"], correct:1, explanation:"A post-incident lessons learned review identifies what worked, what failed, and what can be improved to strengthen future prevention and response." },
  { id:10904, domain:4, level:2, question:"Which document defines the roles, responsibilities, and authority of personnel during a security incident?", options:["A Incident response plan","B Security policy","Business impact analysis","Risk register"], correct:0, explanation:"The incident response plan assigns specific roles and responsibilities and grants authority to incident response team members to act decisively during an incident." },
  { id:10905, domain:4, level:3, question:"During a ransomware incident, the incident response team discovers the attacker is still present in the network. What is the MOST appropriate immediate action?", options:["Notify all employees via email","Immediately shut down all systems","C Begin full system restoration from backups","D Contain the incident by isolating affected systems while preserving forensic evidence"], correct:3, explanation:"Isolating affected systems stops lateral movement and further damage while preserving forensic evidence needed for analysis, without tipping off the attacker via broad notification." },
  { id:10906, domain:4, level:1, question:"What does 'mean time to detect' (MTTD) measure in incident management?", options:["A The average time between two consecutive incidents","B The average time from an incident occurring to its detection","C The time from incident containment to full recovery","The time required to restore a system from backup"], correct:1, explanation:"MTTD measures the average elapsed time between when an incident begins and when the security team detects it, indicating detection capability." },
  { id:10907, domain:4, level:2, question:"Which type of incident response exercise tests the plan on paper without involving actual systems?", options:["A Full-scale simulation","Penetration test","C Red team exercise","D Tabletop exercise"], correct:3, explanation:"A tabletop exercise walks participants through an incident scenario in a discussion format without activating actual systems, testing plans and decision-making." },
  { id:10908, domain:4, level:2, question:"What is the primary purpose of incident classification?", options:["To assign financial damages to incidents","B To categorize incidents by severity so resources and response priorities can be allocated appropriately","To document all alerts generated by monitoring tools","D To identify the attacker behind the incident"], correct:1, explanation:"Incident classification assigns severity levels that guide resource allocation and response urgency, ensuring critical incidents receive priority attention." },
  { id:10909, domain:4, level:3, question:"An organization's incident response team receives conflicting instructions from the legal department and the CISO during a major breach. What governance structure BEST prevents this?", options:["Training all team members in legal requirements","B Contracting an external incident response firm","Requiring all decisions to be made by consensus","D Pre-establishing an incident command structure with clear authority and escalation paths"], correct:3, explanation:"A pre-defined incident command structure with clear authority, roles, and escalation paths eliminates confusion and conflicting instructions during high-pressure incidents." },
  { id:10910, domain:4, level:1, question:"What is the purpose of a computer security incident response team (CSIRT)?", options:["A To coordinate and manage the technical response to security incidents","B To conduct routine vulnerability scans","C To develop network infrastructure","To manage the security budget"], correct:0, explanation:"A CSIRT is the designated team responsible for coordinating and executing the technical response to security incidents, including containment, analysis, and recovery." },
  { id:10911, domain:4, level:2, question:"Which concept describes the point in time to which data must be restored following an incident?", options:["Recovery Time Objective (RTO)","B Business Impact Analysis (BIA)","C Recovery Point Objective (RPO)","D Mean Time to Recover (MTTR)"], correct:2, explanation:"RPO defines the acceptable data loss window, specifying the point in time to which systems must be restored, which drives backup frequency decisions." },
  { id:10912, domain:4, level:3, question:"A security analyst suspects a web application is being used as a command-and-control channel. What is the BEST initial investigative action?", options:["Immediately take the web application offline","Review web application logs and network traffic for anomalous patterns","Notify all application users of a potential breach","Perform a full vulnerability scan of the application"], correct:1, explanation:"Reviewing logs and network traffic first confirms the hypothesis and gathers evidence without tipping off the attacker or causing unnecessary service disruption." },
  { id:10913, domain:4, level:1, question:"What is 'chain of custody' in digital forensics?", options:["A The documented, unbroken record of evidence handling from collection to presentation","B The order in which systems are restored after an incident","The sequence of attack steps performed by a threat actor","The process of notifying stakeholders after an incident"], correct:0, explanation:"Chain of custody documents every person who handled evidence and every action taken, ensuring the evidence's integrity and admissibility in legal proceedings." },
  { id:10914, domain:4, level:2, question:"Which incident response phase involves removing malware and closing the vulnerabilities exploited during the attack?", options:["A Eradication","B Preparation","C Detection and analysis","Recovery"], correct:0, explanation:"Eradication involves removing all traces of the threat actor's presence, including malware, backdoors, and exploited vulnerabilities, before systems are returned to production." },
  { id:10915, domain:4, level:3, question:"A CISM practitioner is reviewing the organization's incident response capability. Tabletop exercises consistently reveal communication failures during simulated incidents. What is the BEST corrective action?", options:["Hire additional security analysts","B Purchase a new SIEM solution","C Develop and test a comprehensive communication plan with defined escalation paths and contact lists","Increase frequency of vulnerability scans"], correct:2, explanation:"Communication failures require a dedicated communication plan that defines who contacts whom, through what channels, and in what order during an incident." },
  { id:10916, domain:4, level:2, question:"What is the purpose of threat intelligence in incident management?", options:["To replace the need for security monitoring","B To conduct penetration testing","To automate patch management","D To provide context about threat actors, techniques, and indicators to improve detection and response"], correct:3, explanation:"Threat intelligence provides actionable context about adversary tactics, techniques, and indicators of compromise that enhances detection capabilities and informs response decisions." },
  { id:10917, domain:4, level:1, question:"Which of the following is an example of a technical indicator of compromise (IoC)?", options:["An employee reporting a suspicious email","B policy violation by a contractor","C known malicious IP address found in network logs","A failed login attempt by an authorized user"], correct:2, explanation:"Indicators of compromise are technical artifacts such as malicious IP addresses, file hashes, or domain names that indicate a system may have been compromised." },
  { id:10918, domain:4, level:2, question:"What should be the FIRST action when a security incident is confirmed?", options:["Notify the media","B Conduct a full vulnerability assessment","C Activate the incident response plan and notify the incident response team","D Restore all affected systems from backup"], correct:2, explanation:"Upon incident confirmation, activating the incident response plan and notifying the response team ensures a coordinated, structured response from the outset." },
  { id:10919, domain:4, level:3, question:"An organization suffers a data breach involving personally identifiable information (PII). Within 72 hours of discovery, which obligation is MOST likely mandatory under major privacy regulations?", options:["Publishing a press release","B Restoring all affected systems","C Notifying affected individuals and relevant supervisory authorities","D Completing a full forensic investigation"], correct:2, explanation:"Regulations such as GDPR require notification to supervisory authorities within 72 hours of becoming aware of a personal data breach, with individual notification following." },
  { id:10920, domain:4, level:2, question:"What is the primary purpose of a security information and event management (SIEM) system in incident management?", options:["To encrypt sensitive data","B To deploy patches to endpoint systems","To manage security policies","D To aggregate, correlate, and analyze log data to detect and alert on potential incidents"], correct:3, explanation:"A SIEM aggregates logs from multiple sources, applies correlation rules to detect suspicious patterns, and generates alerts that trigger incident investigation." },
  { id:10921, domain:1, level:2, question:"What is the primary distinction between a security policy and a security procedure?", options:["A Procedures are mandatory; policies are optional","B Policies are technical; procedures are managerial","C Policies state what must be done; procedures describe how to do it","Policies are written by IT; procedures are written by HR"], correct:2, explanation:"A security policy establishes the requirements and objectives (the 'what'), while procedures provide step-by-step instructions for achieving compliance (the 'how')." },
  { id:10922, domain:1, level:3, question:"A board member argues that a proposed security initiative does not support business strategy. What should the CISO do FIRST?", options:["A Demonstrate how the initiative mitigates risks to strategic business objectives","B Implement the initiative without board approval","C Withdraw the proposal immediately","Escalate to the CEO over the board member's objection"], correct:0, explanation:"The CISO should reframe the proposal in business risk terms, showing explicitly how the initiative protects or enables the strategic objectives the board cares about." },
  { id:10923, domain:1, level:1, question:"What is the purpose of an information security steering committee?", options:["A To provide cross-functional executive oversight and decision-making authority for security","B To manage day-to-day security operations","To conduct vulnerability assessments","To review all security incidents"], correct:0, explanation:"A steering committee brings together business and IT leadership to provide governance oversight, strategic direction, and resource allocation decisions for security." },
  { id:10924, domain:1, level:2, question:"Which governance concept ensures that security decisions are made by those with appropriate authority and knowledge?", options:["Confidentiality","B Redundancy","C Authorization and accountability","Non-repudiation"], correct:2, explanation:"Effective governance requires that decisions are made by individuals with both the authority to commit resources and the knowledge to understand implications." },
  { id:10925, domain:1, level:3, question:"An organization operates across multiple jurisdictions with differing data protection laws. What governance approach BEST manages this complexity?", options:["A Create a governance framework that maps requirements per jurisdiction and manages exceptions","B Apply the least restrictive standard to minimize compliance costs","Delegate compliance entirely to local managers","D Apply the strictest standard globally to all jurisdictions"], correct:0, explanation:"A jurisdiction-mapped governance framework identifies applicable requirements for each location and provides a structured way to manage variations while maintaining a consistent baseline." },
  { id:10926, domain:1, level:1, question:"What does 'due diligence' mean in the context of information security governance?", options:["Implementing every available security control","B Passing all regulatory audits","C Eliminating all residual risk","D Taking reasonable steps to understand and address information security risks"], correct:3, explanation:"Due diligence requires that management takes reasonable, informed steps to identify and address security risks, demonstrating responsible stewardship." },
  { id:10927, domain:1, level:2, question:"Which of the following BEST describes the role of a data owner?", options:["A The legal team who manages data privacy obligations","B technical administrator who maintains data backups","The CISO who approves all data access","D business role accountable for defining data classification and appropriate use"], correct:3, explanation:"The data owner is a business-side role accountable for determining how data should be classified, who should access it, and what controls are appropriate." },
  { id:10928, domain:1, level:3, question:"A new regulation requires organizations to appoint a Data Protection Officer (DPO). Where should this role sit within the governance structure to ensure independence?", options:["Reporting to the CISO to consolidate security leadership","Reporting to the CIO for IT coordination","C Reporting directly to senior management or the board, independent of operational IT functions","D Reporting to the legal department only"], correct:2, explanation:"DPO independence is critical; regulations such as GDPR require the DPO to report to the highest management level and not receive instructions that conflict with their duties." },
  { id:10929, domain:1, level:2, question:"What is the purpose of a security governance maturity model?", options:["To rank organizations against their competitors in security spending","B To certify that an organization is fully compliant with all regulations","C To assess the current state of governance practices and identify areas for structured improvement","To replace annual security audits"], correct:2, explanation:"A governance maturity model provides a structured scale to assess current capabilities and a roadmap for systematically improving governance practices over time." },
  { id:10930, domain:1, level:1, question:"What is the primary benefit of having clearly defined security roles and responsibilities?", options:["It reduces the need for security tools","B It guarantees regulatory compliance","It eliminates the need for security training","D It ensures accountability and prevents gaps or overlaps in security coverage"], correct:3, explanation:"Clear role definitions assign accountability for specific security activities, preventing both gaps where no one owns a control and overlaps that waste resources." },
  { id:10931, domain:2, level:2, question:"What is the purpose of a Business Impact Analysis (BIA)?", options:["To identify all technical vulnerabilities in systems","B To document all security incidents from the past year","C To determine the criticality of business processes and the impact of their disruption","To assess third-party vendor security posture"], correct:2, explanation:"A BIA identifies critical business processes, quantifies the impact of their disruption, and establishes recovery priorities and objectives (RTO/RPO) for continuity planning." },
  { id:10932, domain:2, level:1, question:"Which risk management concept describes the frequency with which a specific threat event is expected to occur within a year?", options:["A Annual Rate of Occurrence (ARO)","B Maximum Tolerable Downtime (MTD)","Annualized Loss Expectancy (ALE)","D Single Loss Expectancy (SLE)"], correct:0, explanation:"ARO is the estimated frequency with which a given threat event is expected to occur per year, used in quantitative risk calculations." },
  { id:10933, domain:2, level:3, question:"An organization uses a third-party cloud provider. Which risk management document BEST formalizes the security obligations of both parties?", options:["A Privacy policy","B Non-Disclosure Agreement (NDA)","C Service Level Agreement (SLA) with embedded security requirements","Terms of service"], correct:2, explanation:"An SLA with explicit security requirements contractually commits the cloud provider to defined security obligations and the organization to its responsibilities, creating enforceable accountability." },
  { id:10934, domain:2, level:2, question:"What is the purpose of a risk acceptance document?", options:["A To formally record management's informed decision to accept a specific risk without further mitigation","B To document the results of a penetration test","C To authorize the purchase of new security tools","To approve a new business project"], correct:0, explanation:"A risk acceptance document formalizes the decision not to treat a risk further, recording that management is aware of and accepts the residual risk." },
  { id:10935, domain:2, level:1, question:"Which of the following is a proactive risk management activity?", options:["Investigating a security incident after it occurs","B Restoring systems from backup after a ransomware attack","C Conducting a threat assessment before deploying a new system","Notifying regulators of a data breach"], correct:2, explanation:"Conducting a threat assessment before deployment is proactive—it identifies and mitigates risks before they can be exploited, unlike reactive activities that occur after an event." },
  { id:10936, domain:2, level:2, question:"What is the primary risk associated with unmanaged shadow IT?", options:["Increased IT budget","B Improved business agility","C Reduced software licensing costs","D Systems and data that bypass security controls, creating unmonitored risk exposure"], correct:3, explanation:"Shadow IT creates systems and data stores outside organizational oversight, meaning security controls, monitoring, and compliance requirements may not be applied." },
  { id:10937, domain:2, level:3, question:"A risk assessment identifies that a critical business application relies on an end-of-life operating system. Upgrading is projected to take 18 months. What is the BEST interim risk management approach?", options:["A Implement compensating controls such as network isolation and enhanced monitoring while tracking progress against the upgrade timeline","B Delay the upgrade until a new risk assessment is conducted","Immediately decommission the application","D Accept the risk entirely until upgrade is complete"], correct:0, explanation:"Compensating controls reduce residual risk during the upgrade window, while tracking progress ensures the risk treatment plan is being executed as committed." },
  { id:10938, domain:2, level:1, question:"What does 'risk avoidance' mean as a risk treatment strategy?", options:["A Transferring risk to an insurer","Reducing the likelihood of a risk event","C Choosing not to engage in the activity that creates the risk","Monitoring the risk without taking action"], correct:2, explanation:"Risk avoidance eliminates a risk by choosing not to pursue the activity or project that introduces it, accepting the associated business opportunity cost." },
  { id:10939, domain:2, level:2, question:"Which risk assessment approach involves gathering expert opinions from multiple specialists iteratively to reach consensus?", options:["A Delphi technique","B Vulnerability scanning","Fault tree analysis","D Monte Carlo simulation"], correct:0, explanation:"The Delphi technique uses multiple rounds of expert questioning and feedback to converge on a consensus estimate, useful when empirical data is scarce." },
  { id:10940, domain:2, level:3, question:"A risk manager presents a risk heat map showing most risks in the high-likelihood, high-impact quadrant. Senior management accepts all risks without treatment. What should the risk manager do?", options:["Accept management's decision and close the risk register items","B Immediately implement controls without approval","C Escalate to the board, documenting that management's collective acceptance exceeds the stated risk appetite","Resign from the position"], correct:2, explanation:"When management's acceptance decisions collectively exceed the organization's risk appetite, the risk manager has an obligation to escalate to the board for informed oversight." },
  { id:10941, domain:3, level:2, question:"What is the primary objective of a security architecture review?", options:["To count the number of security tools deployed","B To approve all IT project budgets","C To ensure that proposed system designs include appropriate security controls aligned with standards and risk posture","D To conduct penetration testing of production systems"], correct:2, explanation:"Security architecture reviews evaluate whether proposed designs implement security controls proportionate to the risk and consistent with organizational standards before systems are built." },
  { id:10942, domain:3, level:1, question:"What is the purpose of a security baseline configuration?", options:["To define the maximum permissible security settings","B To document all known vulnerabilities","C To establish a minimum set of security configurations required for a given system type","To replace the need for vulnerability scanning"], correct:2, explanation:"A security baseline defines the minimum required security configuration for a system type, ensuring consistent, adequate protection across all instances." },
  { id:10943, domain:3, level:3, question:"A security program manager finds that patching SLAs are consistently missed across business units. What is the MOST effective programmatic solution?", options:["A Hire more security analysts","B Send weekly reminder emails to system owners","C Integrate patch compliance metrics into executive dashboards and tie remediation to change management approvals","Perform more frequent vulnerability scans"], correct:2, explanation:"Visibility in executive dashboards creates accountability at the leadership level, and tying patch compliance to change management approvals creates an operational incentive for timely remediation." },
  { id:10944, domain:3, level:2, question:"Which program management activity ensures that security spending is optimized relative to risk reduction achieved?", options:["Preparing an annual compliance report","B Performing quarterly access reviews","C Conducting security program portfolio management with cost-benefit analysis","Deploying additional monitoring tools"], correct:2, explanation:"Security portfolio management evaluates all security initiatives against their risk reduction benefit and cost, enabling resource allocation to highest-value activities." },
  { id:10945, domain:3, level:1, question:"What is the purpose of a security exception process?", options:["A To replace the policy review process","B To waive all security requirements for senior executives","C To provide a formal, time-limited mechanism to deviate from a security standard with management approval and compensating controls","To document security incidents"], correct:2, explanation:"A formal exception process allows deviations from standards when technically or operationally necessary, with management approval, compensating controls, and a defined expiration date." },
  { id:10946, domain:3, level:2, question:"Which security program element ensures that terminated employees can no longer access organizational systems?", options:["Security awareness training program","B Vulnerability management program","C Network perimeter controls","D Identity and access management lifecycle process including offboarding"], correct:3, explanation:"The offboarding component of the identity and access management lifecycle ensures timely revocation of all access rights when employment ends." },
  { id:10947, domain:3, level:3, question:"A security manager wants to demonstrate program improvement over 18 months to justify continued investment. Which approach BEST supports this?", options:["A Showing trends in maturity assessment scores, KPIs, and risk reduction over the period","B Providing a list of all security incidents","Listing all security tools purchased","Counting the number of policies updated"], correct:0, explanation:"Trend data showing measurable improvement in maturity scores, KPIs, and risk metrics over time provides compelling, objective evidence of program value and progress." },
  { id:10948, domain:3, level:2, question:"What is the primary purpose of a security program gap analysis?", options:["To list all known vulnerabilities in infrastructure","To compare current security capabilities against a target state or framework to identify areas requiring improvement","To document all security incidents from the prior year","To assess employee security awareness levels"], correct:1, explanation:"A gap analysis compares the current program state to a desired target or framework, identifying specific capability gaps that form the basis of an improvement roadmap." },
  { id:10949, domain:3, level:1, question:"What does 'security by design' mean in program development?", options:["Building the most expensive security controls possible","B Designing systems for aesthetics first","Adding security controls after a system is deployed","D Incorporating security requirements and controls from the earliest stages of system design"], correct:3, explanation:"Security by design means embedding security considerations into system design from the outset, reducing the cost and difficulty of achieving security compared to retrofitting controls." },
  { id:10950, domain:3, level:2, question:"Which security program component manages relationships with and security requirements for external organizations that access organizational data or systems?", options:["Incident response program","B Vulnerability management program","C Third-party risk management program","Security awareness training program"], correct:2, explanation:"A third-party risk management program establishes security requirements for vendors and partners, monitors their compliance, and manages risks introduced through external relationships." },
  { id:10951, domain:4, level:3, question:"An organization's incident response team is handling a sophisticated APT intrusion. Forensic analysis reveals the attacker has been present for six months. What is the MOST critical consideration during eradication?", options:["Speed of removal to minimize downtime","B Ensuring all attacker footholds and persistence mechanisms are identified and removed before recovery begins","Notifying all employees immediately","D Conducting a vulnerability scan of the entire network"], correct:1, explanation:"With long-dwell APT intrusions, incomplete eradication allows attackers to maintain access post-recovery; thorough identification of all persistence mechanisms is critical before restoration." },
  { id:10952, domain:4, level:2, question:"What is the purpose of an incident response retainer with an external firm?", options:["A To ensure pre-negotiated access to specialized incident response expertise and resources during a major incident","B To replace the internal incident response team","C To outsource all security operations permanently","To manage day-to-day security monitoring"], correct:0, explanation:"An IR retainer provides pre-established access to external specialists and resources that can be rapidly deployed during incidents that exceed internal team capabilities." },
  { id:10953, domain:4, level:1, question:"What does 'containment' achieve during incident response?", options:["It permanently removes the threat from the environment","B It prevents the incident from spreading or causing additional damage while investigation continues","It restores affected systems to normal operation","D It identifies the root cause of the incident"], correct:1, explanation:"Containment limits the scope and impact of an ongoing incident by isolating affected systems, preventing lateral movement and further damage." },
  { id:10954, domain:4, level:2, question:"Which approach to incident containment carries the LEAST risk of tipping off an advanced attacker?", options:["A Notifying the attacker's ISP","B Immediately blocking all outbound traffic","C Gradually isolating affected systems while continuing to observe attacker behavior","Shutting down all corporate network segments"], correct:2, explanation:"Gradual isolation allows continued observation of attacker behavior for intelligence gathering while limiting damage, without abrupt changes that alert sophisticated attackers to detection." },
  { id:10955, domain:4, level:3, question:"During a major incident, the public affairs team wants to issue a press release disclosing the breach before forensic analysis is complete. What is the BEST response from the CISM practitioner?", options:["A Advise delaying external communication until sufficient facts are confirmed, while meeting any mandatory notification deadlines","B Approve the press release to demonstrate transparency","Refuse all communications until the investigation is fully complete","Issue the press release immediately to control the narrative"], correct:0, explanation:"Premature disclosure of incomplete or inaccurate information can cause legal liability and reputational harm; communications should be factually grounded while meeting regulatory notification timelines." },
  { id:10956, domain:4, level:1, question:"What is the purpose of an incident response playbook?", options:["A To provide step-by-step response procedures for specific incident types","B To serve as the organization's risk register","C To document all security policies","To replace security awareness training"], correct:0, explanation:"Incident response playbooks provide pre-defined, scenario-specific procedures that guide responders through appropriate steps for common incident types, reducing errors under pressure." },
  { id:10957, domain:4, level:2, question:"Which metric BEST measures the speed of an organization's incident response capability?", options:["Number of incidents reported","B Total number of security policies","C Mean Time to Respond (MTTR) from detection to containment","Volume of security log data collected"], correct:2, explanation:"MTTR from detection to containment directly measures how quickly the team responds to confirmed incidents, reflecting response efficiency and effectiveness." },
  { id:10958, domain:4, level:3, question:"An organization's SIEM generates thousands of alerts daily, but the security team can only investigate a fraction. What program change BEST addresses this?", options:["Hire enough analysts to investigate every alert","Disable low-confidence alert rules","C Replace the SIEM with a simpler solution","D Implement alert tuning and risk-based prioritization to focus analyst effort on highest-fidelity, highest-risk alerts"], correct:3, explanation:"Risk-based prioritization and alert tuning reduce noise, directing limited analyst capacity toward the alerts most likely to represent genuine, high-impact threats." },
  { id:10959, domain:4, level:2, question:"What is the primary purpose of a post-incident report?", options:["A To close the incident ticket in the SIEM","B To assign disciplinary actions to responsible employees","To notify regulators of the breach","D To document the incident timeline, impact, response actions, and lessons learned for management and future reference"], correct:3, explanation:"A post-incident report provides a formal record of what happened, how it was handled, the impact, and what improvements should be made, serving both management and future responders." },
  { id:10960, domain:4, level:1, question:"What distinguishes an incident from an event in security operations?", options:["Events always involve external attackers; incidents are always internal","B Incidents are less severe than events","C An event is any observable occurrence; an incident is an event that negatively impacts or threatens information security","Events require immediate escalation; incidents do not"], correct:2, explanation:"An event is any observable system or network occurrence, while an incident is an event that has been determined to have an adverse impact on the confidentiality, integrity, or availability of information." },
  { id:10961, domain:1, level:3, question:"An organization's security program has strong technical controls but employees regularly circumvent policies. What governance issue does this MOST likely indicate?", options:["Insufficient technical controls","B Inadequate penetration testing","C governance failure in security culture, communication, or policy enforcement","Excessive regulatory requirements"], correct:2, explanation:"When employees routinely bypass policies, it signals a governance failure—typically in culture, consequence management, or policy design—rather than a purely technical control gap." },
  { id:10962, domain:1, level:2, question:"Which of the following BEST describes the concept of 'information security governance outcomes'?", options:["A The certifications held by security staff","B The specific security tools deployed by the organization","The budget allocated to the security program","D The results that security governance activities produce, such as strategic alignment, value delivery, and risk management"], correct:3, explanation:"Governance outcomes are the beneficial results of governance activities, including alignment between security and business strategy, optimized resources, and managed risk." },
  { id:10963, domain:1, level:1, question:"What is the primary reason for including business unit leaders on a security steering committee?", options:["To reduce the security team's workload","B To ensure security decisions consider business context and to gain cross-functional support","To eliminate the need for a CISO","D To manage the security budget directly"], correct:1, explanation:"Business unit representation ensures security decisions are informed by operational realities and that business leaders are engaged partners who support security objectives." },
  { id:10964, domain:1, level:2, question:"What does 'value delivery' mean in the context of information security governance?", options:["A Ensuring security investments produce benefits that justify their costs and enable business objectives","B Delivering security reports to the board","C Maximizing the number of security controls implemented","Transferring all risk to third parties"], correct:0, explanation:"Value delivery in governance means security investments produce tangible benefits—risk reduction, compliance enablement, business facilitation—proportionate to their cost." },
  { id:10965, domain:1, level:3, question:"A CISM practitioner discovers that the security strategy was developed without input from business stakeholders and does not address their key risks. What is the BEST corrective action?", options:["Publish the strategy as-is and revise it next year","Conduct stakeholder interviews and a business risk alignment workshop, then revise the strategy","Replace the entire security team","Implement the strategy and wait for feedback"], correct:1, explanation:"Effective security strategy requires understanding business priorities; engaging stakeholders and revising the strategy ensures it addresses actual business risks and gains the support needed for execution." },
  { id:10966, domain:2, level:2, question:"Which element of quantitative risk analysis represents the expected monetary loss each time a specific risk event occurs?", options:["Annual Rate of Occurrence (ARO)","B Single Loss Expectancy (SLE)","Annual Loss Expectancy (ALE)","D Maximum Tolerable Downtime (MTD)"], correct:1, explanation:"SLE represents the expected monetary loss from a single occurrence of a risk event, calculated as asset value multiplied by the exposure factor." },
  { id:10967, domain:2, level:1, question:"What is the purpose of a risk treatment plan?", options:["A To conduct employee security awareness training","B To document all historical security incidents","To approve new security tool purchases","D To define specific actions, owners, timelines, and resources needed to implement chosen risk treatments"], correct:3, explanation:"A risk treatment plan documents the specific remediation steps, assigned owners, target dates, and resources required to implement the selected risk treatment for each identified risk." },
  { id:10968, domain:2, level:3, question:"A newly appointed CISM practitioner reviews the risk register and finds many risks have been in 'accepted' status for years with no reassessment. What is the MOST appropriate action?", options:["A Schedule a reassessment of long-standing accepted risks to determine whether circumstances have changed and acceptance remains appropriate","B Immediately implement controls for all accepted risks","Remove them from the risk register as they are resolved","D Leave them as accepted since management already approved them"], correct:0, explanation:"Risk acceptance requires periodic reassessment because the threat environment, business context, and control landscape change; previously accepted risks may now require treatment." },
  { id:10969, domain:2, level:2, question:"What is the MOST important characteristic of an effective risk management framework?", options:["It uses only quantitative analysis techniques","B It is developed entirely by the security team without business input","C It focuses exclusively on IT risks","D It is integrated into business processes and decision-making rather than treated as a standalone compliance exercise"], correct:3, explanation:"An effective risk management framework is embedded in organizational decision-making, ensuring risk considerations inform business choices rather than existing as a parallel compliance process." },
  { id:10970, domain:2, level:1, question:"What does 'exposure factor' represent in quantitative risk analysis?", options:["The annual frequency of a threat event","B The percentage of an asset's value that would be lost in a risk event","The total number of vulnerabilities identified","D The cost to implement a specific control"], correct:1, explanation:"The exposure factor is the percentage of an asset's value that would be lost if a specific risk event occurred, used with asset value to calculate SLE." },
  { id:10971, domain:3, level:3, question:"An organization's security program has been heavily compliance-focused. The new CISO wants to shift to a risk-based approach. What is the MOST significant challenge to this transition?", options:["A Business stakeholders and auditors accustomed to checklist compliance may resist the ambiguity of risk-based judgments","B Risk-based approaches are more expensive than compliance approaches","C Compliance frameworks are technically superior to risk-based approaches","Regulators prohibit risk-based security programs"], correct:0, explanation:"Transitioning from compliance to risk-based approaches requires cultural change; stakeholders comfortable with binary pass/fail compliance metrics often resist the judgment-based nature of risk management." },
  { id:10972, domain:3, level:2, question:"What is the purpose of a security program performance dashboard?", options:["To replace annual audits","B To provide management with a consolidated, real-time view of security program health and key metrics","C To document all security incidents","To manage security team schedules"], correct:1, explanation:"A security dashboard consolidates key metrics into an accessible format that enables management to monitor program health and make informed decisions." },
  { id:10973, domain:3, level:1, question:"What is the primary benefit of automating repetitive security tasks?", options:["It eliminates the need for security staff","B It reduces human error and frees analyst capacity for higher-value investigative and strategic work","It guarantees regulatory compliance","D It replaces the need for security controls"], correct:1, explanation:"Automation reduces manual error rates in routine tasks and redirects skilled security personnel toward complex, judgment-intensive activities that automation cannot perform." },
  { id:10974, domain:3, level:2, question:"Which of the following BEST describes 'security program integration'?", options:["A Consolidating all security tools onto a single platform","B Purchasing a single vendor's entire security product suite","Merging the security team with the IT operations team","D Embedding security activities into business processes, IT operations, and the project lifecycle rather than operating in isolation"], correct:3, explanation:"Security program integration means security considerations are embedded throughout the organization's processes, enabling consistent protection without being a separate, disconnected function." },
  { id:10975, domain:3, level:3, question:"A security program manager is told that the security team must complete 20% more work with the same headcount. What is the BEST programmatic response?", options:["Accept all work regardless of quality","Prioritize activities by risk impact, automate where possible, and communicate trade-offs to stakeholders","Hire contractors without management approval","Eliminate all proactive security activities to focus on reactive work"], correct:1, explanation:"Resource constraints require risk-based prioritization to focus effort where it matters most, automation to increase capacity, and transparent communication with stakeholders about the trade-offs." },
  { id:10976, domain:4, level:2, question:"What is the purpose of threat hunting in incident management?", options:["A To manage the incident response plan","B To respond to alerts generated by the SIEM","C To proactively search for indicators of attacker presence that automated tools have not yet detected","To conduct annual security audits"], correct:2, explanation:"Threat hunting uses analyst-driven investigation techniques to proactively find threats that evade automated detection, reducing attacker dwell time." },
  { id:10977, domain:4, level:1, question:"What does 'eradication' involve in the incident response lifecycle?", options:["Formally closing the incident ticket","B Removing all malicious artifacts, attacker access, and exploited vulnerabilities from the affected environment","Restoring systems to normal operations","D Notifying regulators of the incident"], correct:1, explanation:"Eradication removes all traces of the attacker's presence—malware, backdoors, compromised credentials, and exploited vulnerabilities—before systems are restored." },
  { id:10978, domain:4, level:3, question:"During a breach investigation, the forensic team discovers evidence that an insider threat exfiltrated intellectual property over 12 months. What is the MOST important governance consideration for the CISM practitioner?", options:["A Immediately terminate the employee and close the case","B Coordinate with legal, HR, and law enforcement while preserving forensic evidence integrity for potential prosecution","Notify all employees of the insider threat","Conduct a full vulnerability scan of the organization"], correct:1, explanation:"Insider threat cases require cross-functional coordination to preserve evidence for legal action, manage HR and legal obligations, and engage law enforcement appropriately." },
  { id:10979, domain:4, level:2, question:"What is the primary purpose of a security event log aggregation and retention policy?", options:["A To ensure sufficient log data is available for incident investigation, forensics, and compliance requirements","B To provide real-time dashboards for the security team","C To save storage space by deleting logs quickly","To automate incident response actions"], correct:0, explanation:"Log retention policies ensure that sufficient historical data is available to reconstruct incident timelines, meet regulatory requirements, and support forensic investigations." },
  { id:10980, domain:4, level:1, question:"What distinguishes a 'critical' incident classification from a 'high' incident classification in most frameworks?", options:["A Critical incidents involve external attackers; high incidents are internal","B Critical incidents have immediate, organization-wide business impact or imminent existential risk; high incidents have significant but contained impact","Critical incidents require no escalation; high incidents require executive notification","They are interchangeable terms"], correct:1, explanation:"Critical classification typically indicates incidents with immediate potential for catastrophic, organization-wide impact requiring executive involvement and crisis management protocols." },
  { id:10981, domain:1, level:2, question:"What is the relationship between information security governance and regulatory compliance?", options:["Compliance is sufficient to achieve good governance","B Governance and compliance are identical concepts","C Good governance typically produces compliance as a byproduct, but compliance alone does not constitute good governance","Regulatory compliance supersedes governance requirements"], correct:2, explanation:"Effective governance creates the conditions under which compliance is achieved; however, an organization can be technically compliant while still having poor governance and security outcomes." },
  { id:10982, domain:1, level:3, question:"A CISM practitioner identifies that the current security strategy prioritizes compliance over risk management. What recommendation should be made to executive leadership?", options:["A Hire a compliance officer to separate the functions","B Maintain the compliance focus as it satisfies all security requirements","Eliminate compliance activities in favor of pure risk management","D Evolve the strategy to be risk-based, using compliance as a floor rather than a ceiling, to better protect against actual threats"], correct:3, explanation:"A risk-based strategy addresses actual threats proportionately while compliance activities ensure minimum legal obligations are met, providing better overall protection than compliance alone." },
  { id:10983, domain:2, level:3, question:"An organization's risk management process identifies a high risk with no feasible mitigation. What are the MOST appropriate next steps?", options:["Ignore the risk as there is nothing to do","B Transfer the risk to a third party without documentation","Immediately cease the business activity that creates the risk","D Formally document the risk, present it to senior management for acceptance, and identify any partial mitigations or monitoring capabilities"], correct:3, explanation:"Even when full mitigation is not feasible, formal documentation and senior management acceptance ensures informed decision-making, and partial mitigations or monitoring can reduce impact." },
  { id:10984, domain:2, level:1, question:"What is the primary reason for conducting regular risk reassessments?", options:["A To ensure the risk register reflects current threats, vulnerabilities, and business context, which change over time","B To identify new compliance requirements","To justify the security budget annually","D To satisfy auditors with documentation"], correct:0, explanation:"The risk landscape changes continuously; regular reassessments ensure identified risks, their ratings, and treatment statuses remain current and relevant to actual conditions." },
  { id:10985, domain:3, level:2, question:"What is the primary purpose of a security program communication plan?", options:["To document all security incidents","B To replace security awareness training","To manage media inquiries during incidents","D To ensure stakeholders receive timely, relevant security information appropriate to their role and decision-making needs"], correct:3, explanation:"A security communication plan ensures the right information reaches the right audiences—executives, business units, end users—in formats and at frequencies that support their needs." },
  { id:10986, domain:3, level:1, question:"What is the purpose of role-based security training?", options:["A To provide training content targeted to the specific security responsibilities and risks relevant to each employee's role","B To replace the general security awareness program","C To deliver identical security training to all employees","To certify employees in information security"], correct:0, explanation:"Role-based training ensures that employees with elevated security responsibilities, such as developers, system administrators, and managers, receive training relevant to their specific risk exposure." },
  { id:10987, domain:4, level:2, question:"What is the purpose of a cyber crisis management plan?", options:["A To automate incident detection and response","B To document all routine security incidents","To replace the technical incident response plan","D To provide governance and communication procedures for managing major cyber incidents at the executive and board level"], correct:3, explanation:"A cyber crisis management plan addresses the executive-level governance, communication, and decision-making processes needed when a cyber incident reaches crisis proportions." },
  { id:10988, domain:4, level:3, question:"After a significant incident, the incident response team concludes that the initial detection took three weeks due to inadequate logging. What program change has the HIGHEST impact on preventing recurrence?", options:["A Implementing comprehensive log collection and centralized SIEM monitoring with tuned detection rules","B Increasing headcount in the security operations center","Conducting more frequent vulnerability scans","Updating the incident response policy"], correct:0, explanation:"Three-week detection delay caused by logging gaps requires foundational improvement in log collection and SIEM detection capabilities to address the root cause." },
  { id:10989, domain:4, level:1, question:"What is the primary benefit of having a pre-established relationship with law enforcement agencies before an incident occurs?", options:["It guarantees immunity from regulatory penalties","B It replaces the need for an incident response plan","C It accelerates the ability to engage law enforcement quickly with established contacts and processes during an actual incident","D It transfers legal liability to law enforcement"], correct:2, explanation:"Pre-established relationships with law enforcement reduce friction during incident response, enabling faster engagement and more effective collaboration when a real incident occurs." },
  { id:10990, domain:4, level:2, question:"Which phase of the incident response lifecycle is MOST dependent on the quality of the preparation phase?", options:["A All subsequent phases","B Detection and analysis","Recovery","D Eradication"], correct:0, explanation:"Preparation defines the plans, tools, contacts, training, and processes used in every subsequent phase; inadequate preparation degrades the effectiveness of detection, containment, eradication, and recovery." },
  { id:10991, domain:1, level:1, question:"What is the primary purpose of an annual information security report to the board?", options:["A To provide executive leadership with strategic-level visibility into security posture, risks, and program performance","B To replace the security steering committee","C To detail every technical vulnerability discovered","To document all employee security violations"], correct:0, explanation:"The annual board report communicates security program performance, material risks, and strategic recommendations at the level of detail appropriate for board-level oversight and decision-making." },
  { id:10992, domain:2, level:2, question:"What is the primary purpose of a security risk dashboard for executives?", options:["A To provide detailed technical vulnerability data","B To give executives a concise, business-oriented view of the organization's most significant risks and their status","To replace the risk register","To automate risk treatment decisions"], correct:1, explanation:"Executive risk dashboards translate technical risk data into business-relevant summaries that enable senior leaders to understand and make informed decisions about the organization's risk posture." },
  { id:10993, domain:3, level:2, question:"What is the MOST effective way to ensure security policies remain current and relevant?", options:["A Delegating policy maintenance entirely to legal counsel","B Publishing policies once and keeping them unchanged for stability","C Establishing a formal policy review cycle, triggering reviews on significant events, and assigning ownership to accountable individuals","Reviewing policies only when requested by auditors"], correct:2, explanation:"A formal review cycle with event-triggered reviews and clear ownership ensures policies are updated proactively and remain aligned with current risks, regulations, and business changes." },
  { id:10994, domain:4, level:3, question:"An organization experiences simultaneous ransomware attacks on its primary data center and backup systems. What incident response challenge does this MOST directly highlight?", options:["Insufficient security monitoring","B Poor security awareness among employees","C Inadequate backup resilience and recovery architecture that failed to protect against simultaneous primary and backup compromise","Lack of an incident response plan"], correct:2, explanation:"Simultaneous compromise of primary and backup systems reveals architectural failures in backup isolation and resilience, requiring a fundamental review of backup security and recovery design." },
  { id:10995, domain:1, level:2, question:"What is the significance of a security program's alignment with business continuity objectives?", options:["A It is primarily a regulatory compliance requirement","B It is only relevant for financial services organizations","It replaces the need for a separate BCM program","D It ensures that security controls support the ability to sustain critical business operations during and after disruptions"], correct:3, explanation:"Security alignment with BCM objectives ensures that security controls protect the systems and processes that sustain critical operations, and that security considerations are embedded in continuity planning." },
  { id:10996, domain:2, level:1, question:"What is the primary purpose of a control self-assessment?", options:["To conduct an external audit of security controls","To enable business units to evaluate the effectiveness of their own security controls and identify gaps","To replace penetration testing","To automate vulnerability management"], correct:1, explanation:"Control self-assessments empower business units to evaluate their own controls, building risk ownership and providing the security team with broader control coverage than a centralized team alone can achieve." },
  { id:10997, domain:3, level:3, question:"A security program manager is tasked with demonstrating continuous improvement to satisfy a new regulatory requirement. Which approach is MOST effective?", options:["A Submitting the security policy to regulators for review","B Publishing a list of all security tools purchased in the past year","C Providing a before-and-after maturity assessment, supported by trend data on key metrics, showing measurable improvement over a defined period","Providing the number of security incidents handled"], correct:2, explanation:"Maturity assessments combined with metric trends provide objective, structured evidence of improvement over time, which is the most credible demonstration of continuous improvement to regulators." },
  { id:10998, domain:4, level:2, question:"What is the primary purpose of incident simulation exercises that involve senior leadership?", options:["To test technical recovery procedures","B To ensure executives understand their roles, communication responsibilities, and decision-making authority during a major incident","To identify vulnerabilities in production systems","D To replace the incident response plan"], correct:1, explanation:"Senior leadership exercises ensure executives are prepared to make timely, effective decisions and communicate appropriately during crisis-level incidents, a critical governance dimension of incident preparedness." },
  { id:10999, domain:1, level:3, question:"A regulatory examination finds that the organization's security governance lacks evidence of board-level oversight. What is the MOST effective corrective action?", options:["Create retroactive documentation of board decisions","B Hire additional compliance staff","C Establish a formal board security committee, implement a reporting cadence with documented minutes, and create a board security briefing program","Implement more technical security controls"], correct:2, explanation:"Regulatory examiners require evidence of genuine, ongoing board oversight; establishing formal committee structure, reporting cadence, and documented oversight activities creates sustainable evidence." },
  { id:11000, domain:3, level:2, question:"What is the PRIMARY reason security programs should be integrated with enterprise risk management (ERM) rather than operating independently?", options:["It reduces the security team's budget","B Integration ensures security risks are considered alongside other enterprise risks, enabling coordinated risk decisions and appropriate prioritization at the organizational level","C It eliminates the need for a separate risk register","It replaces the need for a security steering committee"], correct:1, explanation:"Integration with ERM ensures security risks are visible and comparable to other enterprise risks, enabling informed trade-off decisions and ensuring security receives appropriate prioritization in organizational strategy." },
  { id:11001, domain:1, level:3, question:"A newly appointed CISO finds the security strategy was last updated three years ago and no longer reflects the current threat landscape. The FIRST action should be:", options:["A Immediately implement new security tools to address emerging threats","B Request an emergency budget increase from the board","C Hire additional security staff to address the identified gaps","D Conduct a gap analysis comparing current strategy to present-day business objectives and threat environment"], correct:3, explanation:"A gap analysis identifies specific misalignments between the existing strategy and current needs, providing the factual basis for updating the strategy rather than making ad hoc changes or investments." },
  { id:11002, domain:2, level:2, question:"Which risk treatment option is MOST appropriate when the cost of mitigating a risk exceeds the potential loss from the risk materializing?", options:["A Risk avoidance by discontinuing the activity that creates the risk","B Risk transfer by purchasing cyber insurance to cover all potential losses","C Risk acceptance with documented rationale and owner accountability","D Risk mitigation by implementing additional compensating controls"], correct:2, explanation:"When mitigation cost exceeds expected loss, risk acceptance with documented rationale and accountability is the economically rational treatment, as long as the residual risk falls within the organization's defined risk tolerance." },
  { id:11003, domain:3, level:1, question:"Which document formally establishes the security program's authority, scope, and objectives within an organization?", options:["A The information security policy approved by executive management","B The security risk register listing all identified risks","C The security program charter signed by the CISO","D The business continuity plan covering emergency operations"], correct:0, explanation:"The information security policy approved by executive management formally establishes the program's authority, defines scope, assigns accountability, and sets overarching objectives that all other security documents support." },
  { id:11004, domain:4, level:2, question:"During a ransomware incident, the response team discovers that the backup systems are also encrypted. Which recovery action should be taken NEXT?", options:["A Pay the ransom to obtain the decryption key from the attackers","B Activate a pre-negotiated cyber insurance claim to fund recovery","C Rebuild all affected systems from scratch using vendor installation media","D Invoke the disaster recovery plan using the most recent clean offline backup"], correct:3, explanation:"When primary backups are compromised, the DR plan should guide recovery from the last clean offline or air-gapped backup; paying ransom does not guarantee recovery and should be a last resort after all other options are exhausted." },
  { id:11005, domain:1, level:2, question:"An information security steering committee is MOST effective when it includes which combination of members?", options:["A Only technical security staff from the IT and security departments","B Only senior executives including the CEO, CFO, and board representatives","C Cross-functional representatives from IT, legal, HR, finance, and business units with executive sponsorship","D Only the CISO and direct security team with occasional legal representation"], correct:2, explanation:"Cross-functional membership ensures security decisions reflect business priorities across all areas while executive sponsorship provides authority to allocate resources and resolve conflicts between departments." },
  { id:11006, domain:2, level:3, question:"An organization accepts a significant cybersecurity risk without implementing controls. Six months later the risk materializes causing a major breach. Which governance failure does this MOST represent?", options:["A Inadequate technical security controls in the affected system","B Poor incident response planning and execution","C Insufficient budget allocated to the security program","D Failure to obtain documented board-level approval and ongoing monitoring of the accepted risk"], correct:3, explanation:"Risk acceptance must be formally documented with board-level visibility, defined review periods, and owner accountability. Accepting risk without documented approval and monitoring represents a governance failure, not just a control gap." },
  { id:11007, domain:3, level:2, question:"Which metric BEST measures the effectiveness of a security awareness training program?", options:["A The number of employees who completed the annual training module","B The cost per employee of the security awareness training program","C The total hours of security training delivered across the organization","D Reduction in successful phishing simulations and security incidents attributable to human error"], correct:3, explanation:"Behavioral change metrics such as reduced phishing click rates and fewer human-error incidents measure actual program effectiveness, unlike completion rates which only measure participation." },
  { id:11008, domain:4, level:1, question:"Which phase of the incident response lifecycle focuses on restoring systems to normal operation after containment and eradication?", options:["A Preparation phase establishing policies and response team capabilities","B Detection and analysis phase identifying and validating the incident","C Post-incident activity phase conducting lessons learned review","D Recovery phase restoring affected systems and services to operation"], correct:3, explanation:"The Recovery phase involves restoring systems, verifying integrity, monitoring for recurrence, and returning services to normal operation after the threat has been contained and eradicated." },
  { id:11009, domain:1, level:3, question:"A board member asks the CISO how security investments reduce business risk. The MOST effective response uses:", options:["A Technical metrics such as number of patches applied and vulnerabilities remediated","B Business risk language showing how investments reduce financial exposure and protect revenue","C Compliance status reports showing percentage of controls that are implemented","D Incident counts and comparison to prior year statistics"], correct:1, explanation:"Board members think in business terms; translating security investments into reduced financial exposure and quantified risk reduction enables meaningful risk-informed decision making at board level." },
  { id:11010, domain:2, level:1, question:"Which of the following BEST describes the concept of 'risk appetite' in information security governance?", options:["A The total amount of risk an organization faces from all threat sources","B The maximum financial loss the organization can absorb from a security incident","C The level of risk an organization is willing to accept in pursuit of its objectives","D The residual risk remaining after all controls have been implemented"], correct:2, explanation:"Risk appetite is the amount and type of risk an organization is prepared to accept while pursuing its strategic objectives, set by the board and used to guide risk treatment decisions throughout the organization." },
  { id:11011, domain:3, level:2, question:"An organization's security program has implemented all required controls but a penetration test reveals multiple exploitable vulnerabilities. This MOST likely indicates a failure in which component?", options:["A The information security policy documentation and approval process","B Vulnerability management and continuous assurance testing processes","C Security awareness training for employees and contractors","D The security budget allocation and vendor management process"], correct:1, explanation:"Exploitable vulnerabilities discovered after controls are implemented indicate failures in ongoing vulnerability management — scanning, prioritization, and remediation tracking — not in policy or awareness." },
  { id:11012, domain:4, level:3, question:"After a significant data breach, the legal team advises preserving all evidence for potential litigation. Which incident response activity is MOST critical during this phase?", options:["A Rebuilding all affected systems as quickly as possible to restore operations","B Deleting affected log files to prevent further data exposure","C Notifying all customers immediately without coordinating with legal counsel","D Implementing litigation hold procedures and forensic evidence preservation protocols"], correct:3, explanation:"Litigation holds legally obligate organizations to preserve all potentially relevant evidence; forensic preservation using write-blockers and chain-of-custody procedures ensures evidence admissibility and protects the organization's legal position." },
  { id:11013, domain:1, level:1, question:"Which governance document provides the HIGHEST level of authority for an information security program?", options:["A Information security policy approved by the board or executive management","B Security standards defining mandatory technical specifications","C Security procedures detailing step-by-step operational instructions","D Security guidelines offering recommended but optional best practices"], correct:0, explanation:"The information security policy, approved by the board or executive management, sits at the top of the governance hierarchy, providing the authority and mandate under which all standards, procedures, and guidelines are developed." },
  { id:11014, domain:2, level:2, question:"A critical vulnerability in a payment system has high likelihood and high impact. The business owner insists on accepting the risk due to cost concerns. The CISM's BEST response is:", options:["A Document the risk acceptance formally with business owner sign-off and escalate to an executive","B Accept the decision and remove the risk from the register to avoid further discussion","C Immediately implement the required controls without business owner approval","D Engage the external auditor to force the business owner to remediate the vulnerability"], correct:0, explanation:"CISM best practice requires formal, documented risk acceptance with accountable owner sign-off; when risk exceeds normal tolerance, escalation to executive level ensures appropriate oversight." },
  { id:11015, domain:3, level:3, question:"An organization acquires a company and must integrate its security program. The FIRST step in the integration should be:", options:["A Immediately replacing all acquired company security tools with parent company standards","B Conducting a security assessment of the acquired company to understand its posture and risks","C Terminating the acquired company's CISO and security team immediately","D Applying all parent company security policies to the acquired company on day one"], correct:1, explanation:"A security assessment of the acquired entity establishes baseline posture, identifies critical gaps and inherited risks, and provides the factual foundation for a rational, risk-based integration roadmap." },
  { id:11016, domain:4, level:2, question:"Which factor MOST directly determines whether a security incident should be classified as a breach requiring regulatory notification?", options:["A The dollar value of assets affected by the security incident","B The number of systems affected by the security incident","C The duration of the incident before detection and containment","D Whether unauthorized access to or exfiltration of personal or regulated data occurred"], correct:3, explanation:"Breach notification requirements are triggered by unauthorized access to personal data under GDPR and CCPA, or regulated data under HIPAA and PCI DSS — not by incident cost, duration, or system count." },
  { id:11017, domain:1, level:2, question:"Which of the following BEST supports the business case for investing in a security governance program?", options:["A Demonstrating the number of security incidents prevented through technical controls","B Presenting the total number of security policies and procedures in place","C Quantifying security risk reduction in financial terms aligned to business objectives","D Comparing the organization's security budget to industry peers"], correct:2, explanation:"Quantifying risk reduction in financial terms — reduced expected losses, lower insurance premiums, avoided regulatory fines — creates a compelling business case by speaking the language of business value." },
  { id:11018, domain:2, level:1, question:"Which of the following is a KEY input to the risk assessment process?", options:["A The organization's current security budget allocation by control category","B Asset inventory with assigned classifications and business value ratings","C The security team's preferred control frameworks and standards","D The number of security incidents experienced in the prior year"], correct:1, explanation:"Asset inventory with classifications and business value is fundamental to risk assessment because risk cannot be quantified without knowing what assets exist, how sensitive they are, and what their loss would cost." },
  { id:11019, domain:3, level:2, question:"A security program manager notices that security metrics consistently meet targets but incidents continue to occur. This MOST likely indicates:", options:["A The incident response team is not handling incidents properly","B The metrics being tracked measure outputs rather than security outcomes","C The security budget is insufficient to address all identified risks","D External attackers are specifically targeting the organization"], correct:1, explanation:"Metrics measuring activity volumes rather than outcomes can show positive results while security effectiveness declines — a vanity metrics problem requiring a shift to outcome-focused measurement." },
  { id:11020, domain:4, level:1, question:"Which of the following is the PRIMARY benefit of conducting post-incident reviews after a security incident?", options:["A Identifying employees responsible for security failures for disciplinary action","B Calculating the financial cost of the incident for insurance purposes","C Documenting incidents for regulatory reporting and compliance purposes","D Improving the incident response process by applying lessons learned to future incidents"], correct:3, explanation:"Post-incident reviews are fundamentally improvement exercises — their primary benefit is identifying what worked, what failed, and how procedures can be updated to improve detection, containment, and recovery in future incidents." },
  { id:11021, domain:1, level:3, question:"A security manager must align the security program to support an organizational shift to agile development. The MOST critical change to the governance model is:", options:["A Requiring all agile teams to submit code for security review before each sprint","B Embedding security requirements, testing, and oversight directly into the agile development workflow","C Prohibiting agile development for projects involving sensitive data processing","D Maintaining the existing security review process as a gate before each release"], correct:1, explanation:"Embedding security into agile workflows — security stories in backlog, automated testing in CI/CD, security champions in teams — enables security to keep pace with agile velocity rather than becoming a bottleneck." },
  { id:11022, domain:2, level:2, question:"An organization identifies a risk that cannot be sufficiently mitigated and falls outside its risk appetite. Which risk treatment is MOST appropriate?", options:["A Avoid the risk by discontinuing the activity that creates the unacceptable exposure","B Accept the risk and document it in the risk register for annual review","C Transfer the risk entirely through a cyber insurance policy","D Mitigate the risk to an acceptable level regardless of cost"], correct:0, explanation:"When risk cannot be reduced to acceptable levels and falls outside risk appetite, risk avoidance — stopping the risk-generating activity — is the appropriate treatment; transfer still leaves residual exposure." },
  { id:11023, domain:3, level:1, question:"Which of the following is the PRIMARY purpose of security baselines in an information security program?", options:["A To document the minimum acceptable security configuration for systems and services","B To measure the security team's performance against industry benchmarks","C To establish the maximum security level achievable for all systems","D To define the security investment required for each system type"], correct:0, explanation:"Security baselines define the minimum acceptable security configuration (hardening standards) that all systems must meet, providing a consistent foundation for system security management." },
  { id:11024, domain:4, level:3, question:"During a major incident, the incident commander learns that key personnel are unavailable. Which preparedness control would MOST effectively address this scenario?", options:["A Maintaining a contact list of all security team members with home phone numbers","B Requiring all team members to be available 24/7 during elevated threat periods","C Developing cross-trained backup personnel with documented role-specific response playbooks","D Contracting with an external incident response firm for all future incidents"], correct:2, explanation:"Cross-trained backup personnel with role-specific playbooks ensure continuity regardless of individual availability, enabling consistent incident response without creating single points of failure." },
  { id:11025, domain:1, level:2, question:"Which action BEST demonstrates effective information security governance at the board level?", options:["A The board approving the annual security budget request from the CISO","B The board delegating all security decisions to the CISO without further oversight","C Regular board-level review of security risk posture with documented oversight decisions","D Annual briefings on the number of security incidents and patches applied"], correct:2, explanation:"Effective board governance requires regular, substantive oversight — reviewing risk posture, questioning the adequacy of investments, and making informed decisions about risk acceptance — not just approving budgets." },
  { id:11026, domain:2, level:1, question:"Which of the following BEST describes the difference between a threat and a vulnerability in risk management?", options:["A A threat is a potential cause of harm while a vulnerability is a weakness that could be exploited","B A threat is a known weakness while a vulnerability is a potential cause of harm","C A threat is always external while a vulnerability always refers to software flaws","D A threat requires a vulnerability to exist while a vulnerability cannot exist without a threat"], correct:0, explanation:"A threat is any potential cause of an unwanted incident; a vulnerability is a weakness in a system or process that a threat could exploit to cause harm — distinct but related risk concepts." },
  { id:11027, domain:3, level:2, question:"An assessment reveals that many security controls exist only on paper and are not actually operating. This represents which type of control failure?", options:["A A design deficiency where controls are incorrectly specified for the risk","B An operating effectiveness failure where controls exist but do not function as intended","C A scope gap where controls do not cover all assets in the environment","D A monitoring failure where controls are operating but not being verified"], correct:1, explanation:"Operating effectiveness failures occur when controls are designed and documented but not actually implemented or functioning in practice — a critical distinction between control design and operation in audit assessments." },
  { id:11028, domain:4, level:2, question:"Which communication element is MOST critical during the initial phase of a major security incident response?", options:["A Detailed technical remediation steps shared with all organizational stakeholders","B Regulatory notification filed before containment activities begin","C Public disclosure to affected customers within the first hour of detection","D Clear escalation criteria and notification channels for informing decision-makers"], correct:3, explanation:"Clear escalation criteria and notification channels ensure decision-makers are engaged at the right time, enabling timely resource authorization and strategic decisions during critical early incident phases." },
  { id:11029, domain:1, level:1, question:"Which of the following BEST describes the relationship between information security governance and information security management?", options:["A Governance and management are interchangeable terms for the same function","B Governance provides strategic direction and oversight while management executes operational activities","C Management sets policy and governance implements technical controls","D Governance is performed by external auditors while management is performed internally"], correct:1, explanation:"Governance is the board and executive function providing strategic direction and accountability; management translates governance decisions into operational programs, processes, and controls — complementary but distinct functions." },
  { id:11030, domain:2, level:3, question:"A risk register shows a critical risk with high likelihood and high impact that has remained unmitigated for 18 months. The CISM's MOST appropriate action is:", options:["A Document the risk again and wait for the next annual risk review","B Transfer the risk to the business owner and remove it from the security register","C Remove the risk from the register since it has not materialized in 18 months","D Escalate the unmitigated critical risk to executive management with a recommended action plan"], correct:3, explanation:"Critical risks remaining unmitigated beyond reasonable timeframes require escalation to ensure appropriate attention, resource allocation, and accountability — the CISM cannot simply document and wait." },
  { id:11031, domain:3, level:2, question:"An organization wants to measure the maturity of its security program. Which framework is MOST appropriate for this purpose?", options:["A ISO 27001 providing a certifiable set of security management requirements","B COBIT 2019 providing IT governance principles and processes","C PCI DSS providing prescriptive controls for payment card environments","D CMMI-based maturity model or NIST CSF implementation tiers for security programs"], correct:3, explanation:"CMMI-based security maturity models and NIST CSF implementation tiers are specifically designed to assess and benchmark the maturity of security program processes, enabling roadmap development." },
  { id:11032, domain:4, level:1, question:"Which of the following BEST describes the purpose of an incident response retainer agreement with an external firm?", options:["A To ensure pre-negotiated access to specialized expertise and resources for major incidents","B To transfer all incident response responsibilities to the external firm","C To satisfy regulatory requirements for incident response documentation","D To reduce the need for internal incident response training and preparation"], correct:0, explanation:"A retainer provides pre-negotiated rates and priority access to forensic and IR specialists, ensuring rapid engagement of specialized expertise during major incidents without the delays of emergency procurement." },
  { id:11033, domain:1, level:2, question:"A CISM practitioner is developing key risk indicators (KRIs) for the security program. Which characteristic is MOST important for effective KRIs?", options:["A KRIs should measure activity volumes such as number of patches and scans completed","B KRIs should focus exclusively on technical security metrics from security tools","C KRIs should be as numerous as possible to capture all aspects of the security environment","D KRIs should provide leading indicators of increasing risk before incidents occur"], correct:3, explanation:"Effective KRIs are leading indicators — metrics that signal rising risk before it materializes into incidents — enabling proactive intervention rather than retrospective reporting of what already happened." },
  { id:11034, domain:2, level:2, question:"When conducting a BIA for information security risk management, which output is MOST important to security program planning?", options:["A The total number of business processes documented in the BIA","B Critical asset identification with RTO/RPO requirements and business impact ratings","C A list of all vendors and third parties supporting business processes","D The security team's assessment of technical vulnerabilities in each system"], correct:1, explanation:"Critical asset identification with RTO/RPO and business impact ratings enables security program prioritization — directing resources toward protecting assets whose loss would most severely impact the business." },
  { id:11035, domain:3, level:3, question:"An organization is implementing a new ERP system. At which stage should the security team be engaged to achieve the BEST security outcome?", options:["A After deployment when the system is ready for security testing","B Before implementation during requirements definition and vendor selection","C During user acceptance testing when the system is nearly complete","D When the security team requests access after the system goes live"], correct:1, explanation:"Security engaged at requirements definition enables security to be designed in — shaping architecture, vendor selection, and configuration — rather than retrofitted after implementation at far greater cost and risk." },
  { id:11036, domain:4, level:2, question:"Which of the following BEST describes the purpose of tabletop exercises in incident response preparedness?", options:["A To identify gaps in plans, procedures, and team coordination through scenario walkthroughs","B To test technical incident response tools and automation capabilities","C To practice technical skills such as forensic analysis and malware analysis","D To satisfy regulatory requirements for annual incident response testing"], correct:0, explanation:"Tabletop exercises test decision-making, communication, and procedural adequacy by walking through realistic scenarios; they reveal plan gaps, unclear responsibilities, and escalation failures before a real incident exposes them." },
  { id:11037, domain:1, level:1, question:"Which of the following BEST describes a 'security culture' in an organization?", options:["A Shared values, beliefs, and behaviors that prioritize security in daily decisions","B The set of technical security controls implemented across the organization","C The formal security policies and procedures documented by the security team","D The security training completion rates across the employee population"], correct:0, explanation:"Security culture encompasses shared values and norms that make security a natural consideration in employees' daily decisions, going beyond documented policies or training completion to reflect genuine security-conscious behavior." },
  { id:11038, domain:2, level:3, question:"An organization's residual risk after implementing controls still exceeds its risk appetite. Which action is MOST appropriate?", options:["A Accept the risk and update the risk appetite to include the current risk level","B Transfer the risk entirely by outsourcing the affected function to a third party","C Remove the risk from the register since no further controls are available","D Re-evaluate control options, consider additional mitigations, or reassess whether the activity should continue"], correct:3, explanation:"When residual risk exceeds appetite after control implementation, the organization must find additional mitigation options, accept with formal executive sign-off, or reassess whether the risk-generating activity should continue." },
  { id:11039, domain:3, level:2, question:"A security program manager is asked to demonstrate ROSI to executive management. The MOST credible approach is:", options:["A Quantifying avoided losses, reduced insurance premiums, and regulatory fine avoidance versus investment cost","B Listing all security certifications and compliance achievements from the past year","C Presenting the number of security incidents handled and resolved by the team","D Comparing the security budget to peer organizations in the same industry"], correct:0, explanation:"ROSI calculations using quantified avoided losses versus investment cost translate security spending into financial business value, speaking the language executives use for investment decisions." },
  { id:11040, domain:4, level:3, question:"During an investigation, evidence suggests a sophisticated nation-state actor. Which action should the CISM take IMMEDIATELY after stabilizing the environment?", options:["A Publish a detailed technical report about the attacker's tools and techniques","B Conduct a public press release to warn other organizations about the threat actor","C Delete all attacker artifacts from systems to prevent further damage","D Engage legal counsel and consider notifying law enforcement before conducting further investigation"], correct:3, explanation:"Nation-state incidents have legal, diplomatic, and law enforcement dimensions requiring immediate legal counsel involvement; preserving evidence and coordinating with authorities before further investigation protects legal interests." }
];
